import pytest
from your_module import YourClass, PreparedRequest  # Replace with actual import

@pytest.fixture
def request_instance():
    instance = YourClass()
    instance.method = "GET"
    instance.url = "http://example.com"
    instance.headers = {"Content-Type": "application/json"}
    instance._cookies = {"session": "abc123"}
    instance.body = "test body"
    instance.hooks = {}
    instance._body_position = 0
    return instance

def test_copy_method(request_instance):
    copied_request = request_instance.copy()
    assert copied_request.method == request_instance.method

def test_copy_url(request_instance):
    copied_request = request_instance.copy()
    assert copied_request.url == request_instance.url

def test_copy_headers(request_instance):
    copied_request = request_instance.copy()
    assert copied_request.headers == request_instance.headers
    assert copied_request.headers is not request_instance.headers  # Ensure it's a copy

def test_copy_cookies(request_instance):
    copied_request = request_instance.copy()
    assert copied_request._cookies == request_instance._cookies
    assert copied_request._cookies is not request_instance._cookies  # Ensure it's a copy

def test_copy_body(request_instance):
    copied_request = request_instance.copy()
    assert copied_request.body == request_instance.body

def test_copy_hooks(request_instance):
    copied_request = request_instance.copy()
    assert copied_request.hooks == request_instance.hooks

def test_copy_body_position(request_instance):
    copied_request = request_instance.copy()
    assert copied_request._body_position == request_instance._body_position

def test_copy_none_headers():
    instance = YourClass()
    instance.headers = None
    copied_request = instance.copy()
    assert copied_request.headers is None

def test_copy_empty_request():
    instance = YourClass()
    instance.method = ""
    instance.url = ""
    instance.headers = {}
    instance._cookies = {}
    instance.body = ""
    instance.hooks = {}
    instance._body_position = 0
    copied_request = instance.copy()
    assert copied_request.method == ""
    assert copied_request.url == ""
    assert copied_request.headers == {}
    assert copied_request._cookies == {}
    assert copied_request.body == ""
    assert copied_request.hooks == {}
    assert copied_request._body_position == 0

