import pytest
from urllib.parse import urlparse, urlunparse

def urldefragauth(url):
    scheme, netloc, path, params, query, fragment = urlparse(url)
    if not netloc:
        netloc, path = path, netloc
    netloc = netloc.rsplit("@", 1)[-1]
    return urlunparse((scheme, netloc, path, params, query, ""))

def test_urldefragauth_basic_url():
    url = "http://user:pass@example.com/path?query#fragment"
    assert urldefragauth(url) == "http://example.com/path?query"

def test_urldefragauth_no_authentication():
    url = "http://example.com/path?query#fragment"
    assert urldefragauth(url) == "http://example.com/path?query"

def test_urldefragauth_no_fragment():
    url = "http://user:pass@example.com/path?query"
    assert urldefragauth(url) == "http://example.com/path?query"

def test_urldefragauth_empty_fragment():
    url = "http://user:pass@example.com/path?query#"
    assert urldefragauth(url) == "http://example.com/path?query"

def test_urldefragauth_no_query_or_fragment():
    url = "http://user:pass@example.com/path"
    assert urldefragauth(url) == "http://example.com/path"

def test_urldefragauth_no_netloc():
    url = "/path/to/resource#fragment"
    assert urldefragauth(url) == "/path/to/resource"

def test_urldefragauth_only_fragment():
    url = "#fragment"
    assert urldefragauth(url) == ""

def test_urldefragauth_scheme_only():
    url = "http://"
    assert urldefragauth(url) == "http://"

def test_urldefragauth_invalid_url():
    url = "invalid_url"
    with pytest.raises(ValueError):
        urldefragauth(url)

def test_urldefragauth_multiple_authentication_parts():
    url = "http://user1:pass1@user2:pass2@example.com/path?query#fragment"
    assert urldefragauth(url) == "http://example.com/path?query"

