import pytest
import arrow
from datetime import datetime, timezone

@pytest.fixture
def utc_arrow():
    return arrow.get(datetime(2023, 10, 1, 12, 0, 0, tzinfo=timezone.utc))

def test_to_us_pacific(utc_arrow):
    result = utc_arrow.to('US/Pacific')
    assert result == arrow.get(datetime(2023, 10, 1, 5, 0, 0, tzinfo=timezone.utc))

def test_to_local(utc_arrow):
    result = utc_arrow.to('local')
    assert result.tzinfo is not None

def test_to_negative_offset(utc_arrow):
    result = utc_arrow.to('-07:00')
    assert result == arrow.get(datetime(2023, 10, 1, 5, 0, 0, tzinfo=timezone.utc))

def test_to_invalid_timezone_string(utc_arrow):
    with pytest.raises(ValueError):
        utc_arrow.to('Invalid/Timezone')

def test_to_none_timezone(utc_arrow):
    with pytest.raises(TypeError):
        utc_arrow.to(None)

def test_to_local_timezone(utc_arrow):
    local_tz = arrow.now().tzinfo
    result = utc_arrow.to(local_tz)
    assert result.tzinfo == local_tz

def test_to_utc(utc_arrow):
    result = utc_arrow.to('utc')
    assert result == utc_arrow

def test_to_fold(utc_arrow):
    dt = arrow.get(datetime(2023, 10, 1, 12, 0, 0, tzinfo=timezone.utc))
    result = dt.to('US/Pacific')
    assert result.fold == 0

def test_to_invalid_type(utc_arrow):
    with pytest.raises(TypeError):
        utc_arrow.to(123)

def test_to_empty_string(utc_arrow):
    with pytest.raises(ValueError):
        utc_arrow.to('')

