class TestTimeFrameFormatter:
    @pytest.fixture
    def formatter(self):
        class MockFormatter:
            timeframes = {
                "day": {
                    "single": "{} day",
                    "double": "{} days",
                    "higher": "{} days"
                },
                "hour": {
                    "single": "{} hour",
                    "double": "{} hours",
                    "higher": "{} hours"
                }
            }

            def _format_timeframe(self, timeframe, delta):
                form = self.timeframes[timeframe]
                delta = abs(delta)
                if isinstance(form, Mapping):
                    if 1 < delta <= 4:
                        form = form["double"]
                    else:
                        form = form["higher"]
                return form.format(delta)

        return MockFormatter()

