import pytest

class TestMeridian:
    @pytest.fixture
    def meridian_instance(self):
        class Meridian:
            def __init__(self):
                self.meridians = {"am": "am", "pm": "pm", "AM": "AM", "PM": "PM"}

            def meridian(self, hour: int, token: Any) -> Optional[str]:
                if token == "a":
                    return self.meridians["am"] if hour < 12 else self.meridians["pm"]
                if token == "A":
                    return self.meridians["AM"] if hour < 12 else self.meridians["PM"]
                return None

        return Meridian()

    def test_meridian_am_lowercase(self, meridian_instance):
        assert meridian_instance.meridian(10, "a") == "am"

    def test_meridian_pm_lowercase(self, meridian_instance):
        assert meridian_instance.meridian(15, "a") == "pm"

    def test_meridian_am_uppercase(self, meridian_instance):
        assert meridian_instance.meridian(10, "A") == "AM"

    def test_meridian_pm_uppercase(self, meridian_instance):
        assert meridian_instance.meridian(15, "A") == "PM"

    def test_meridian_midnight(self, meridian_instance):
        assert meridian_instance.meridian(0, "a") == "am"
        assert meridian_instance.meridian(0, "A") == "AM"

    def test_meridian_noon(self, meridian_instance):
        assert meridian_instance.meridian(12, "a") == "pm"
        assert meridian_instance.meridian(12, "A") == "PM"

    def test_meridian_invalid_hour(self, meridian_instance):
        with pytest.raises(ValueError):
            meridian_instance.meridian(-1, "a")
        with pytest.raises(ValueError):
            meridian_instance.meridian(24, "A")

    def test_meridian_none_token(self, meridian_instance):
