    class TimeFormatter:
        and_word = "and"

        def _format_timeframe(self, timeframe, delta):
            return f"{delta} {timeframe}" if delta != 0 else ""

        def _format_relative(self, humanized, unit, value):
            return f"{humanized} ago" if value > 0 else f"{humanized} in the future"

    return TimeFormatter()

def test_describe_multi_single_timeframe(time_formatter):
