    result = time_formatter.describe_multi([("hours", -1)])
    assert result == "-1 hours ago"

def test_describe_multi_mixed_timeframes(time_formatter):
    result = time_formatter.describe_multi([("days", 1), ("hours", 5), ("minutes", 30)])
    assert result == "1 days and 5 hours and 30 minutes ago"

