    assert normalize_timestamp(0.0) == 0.0

def test_normalize_timestamp_negative():
    assert normalize_timestamp(-1000.0) == -1000.0

def test_normalize_timestamp_negative_milliseconds():
    assert normalize_timestamp(-1000000.0) == -1000.0

def test_normalize_timestamp_negative_microseconds():
    assert normalize_timestamp(-1000000000.0) == -1000.0

