import pytest
from itertools import islice

def split_into(iterable, sizes):
    it = iter(iterable)
    for size in sizes:
        if size is None:
            yield list(it)
            return
        else:
            yield list(islice(it, size))

def test_split_into_normal_case():
    result = list(split_into([1, 2, 3, 4, 5, 6], [1, 2, 3]))
    assert result == [[1], [2, 3], [4, 5, 6]]

def test_split_into_remaining_items_not_returned():
    result = list(split_into([1, 2, 3, 4, 5, 6], [2, 3]))
    assert result == [[1, 2], [3, 4, 5]]

def test_split_into_overrun_with_empty_lists():
    result = list(split_into([1, 2, 3, 4], [1, 2, 3, 4]))
    assert result == [[1], [2, 3], [4], []]

def test_split_into_none_in_sizes():
    result = list(split_into([1, 2, 3, 4, 5, 6, 7, 8, 9, 0], [2, 3, None]))
    assert result == [[1, 2], [3, 4, 5], [6, 7, 8, 9, 0]]

def test_split_into_empty_iterable():
