class TestIndex:
    @pytest.fixture
    def range_instance(self):
        class Range:
            def __init__(self, start, stop, step):
                self._start = start
                self._stop = stop
                self._step = step
                self._zero = 0
                self._growing = True if step > 0 else False

            def index(self, value):
                if self._growing:
                    if self._start <= value < self._stop:
                        q, r = divmod(value - self._start, self._step)
                        if r == self._zero:
                            return int(q)
                else:
                    if self._start >= value > self._stop:
                        q, r = divmod(self._start - value, -self._step)
                        if r == self._zero:
                            return int(q)

                raise ValueError(f"{value} is not in numeric range")

        return Range

    def test_index_growing_range(self, range_instance):
        instance = range_instance(0, 10, 2)
        assert instance.index(0) == 0
        assert instance.index(2) == 1
        assert instance.index(8) == 4

    def test_index_growing_range_non_multiple(self, range_instance):
        instance = range_instance(0, 10, 2)
        with pytest.raises(ValueError):
            instance.index(1)

